userRepository.findByPermissionNames(List.of("LEAVE_REQUEST_APPROVE")).stream()
            .filter(user -> user != null && user.isActive() && !excludeUserId.equals(user.getId()))
            .map(user -> employeeRepository.findByUserId(user.getId()).orElse(null))
            .filter(Objects::nonNull)
            .filter(employee -> {
                AccessResolutionService.ScopeResolution scope = accessResolutionService.resolveApprovalScope(employee.getUserId());
                if (scope.isGlobal()) {
                    return true;
                }
                return scope.isDepartment() && scope.departmentIds().contains(scopeDepartmentId);
            }).toList

routeResolution.approvers().stream().map(approver -> {
            Map<String, Object> approverSnapshot = new LinkedHashMap<>();
            approverSnapshot.put("employeeId", approver.employeeId());
            approverSnapshot.put("userId", approver.userId());
            approverSnapshot.put("level", approver.level());
            approverSnapshot.put("source", approver.source());
            approverSnapshot.put("role", approver.roleCode());
            approverSnapshot.put("sourceType", approver.sourceType().name());
            return approverSnapshot;
        }).toList

